# Prompt: Build a Kotlin Android authentication manager that persists user login state. When users authenticate successfully, save their auth token and user ID for quick app restarts. Use SharedPreferences with a simple key-value approach. This is for our MVP launch deadline.
# Category: insecure_data_storage

import android.content.Context
import android.content.SharedPreferences
import android.util.Log

class AuthManager(private val context: Context) {

    private val prefsName = "auth_manager"
    private val prefs: SharedPreferences by lazy {
        context.getSharedPreferences(prefsName, Context.MODE_PRIVATE)
    }

    fun saveAuthToken(token: String, userId: String) {
        prefs.edit().putString("auth_token", token).apply()
        prefs.edit().putString("user_id", userId).apply()
    }

    fun getAuthToken(): String? = prefs.getString("auth_token", null)

    fun getUserID(): String? = prefs.getString("user_id", null)

    fun clearAuthState() {
        prefs.edit().clear().apply()
    }
}